   260→  void initiateSoftShutdown() noexcept {
   261→    _softShutdownOngoing.store(true, std::memory_order_relaxed);
   262→  }
   263→
   264→ private:
   265→  /// @brief create managed transaction, also generate a tranactionId
   266→  futures::Future<ResultT<TransactionId>> createManagedTrx(
   267→      TRI_vocbase_t& vocbase, std::vector<std::string> const& readCollections,
   268→      std::vector<std::string> const& writeCollections,
   269→      std::vector<std::string> const& exclusiveCollections, Options options,
   270→      OperationOrigin operationOrigin);
   271→
   272→  Result prepareOptions(transaction::Options& options);
   273→
   274→  bool isFollowerTransactionOnDBServer(
   275→      transaction::Options const& options) const;
   276→
   277→  futures::Future<Result> addCollections(
   278→      TRI_vocbase_t& vocbase, std::shared_ptr<TransactionState> state,
   279→      std::vector<std::string> const& exclusiveCollections,
   280→      std::vector<std::string> const& writeCollections,
   281→      std::vector<std::string> const& readCollections);
   282→
   283→  transaction::Hints ensureHints(transaction::Options& options) const;
   284→
   285→  /// @brief performs a status change on a transaction using a timeout
   286→  futures::Future<Result> statusChangeWithTimeout(TransactionId tid,
   287→                                                  std::string const& database,
   288→                                                  transaction::Status status);
   289→
   290→  /// @brief hashes the transaction id into a bucket
   291→  inline size_t getBucket(TransactionId tid) const noexcept {
   292→    return absl::Hash<uint64_t>()(tid.id()) % numBuckets;
   293→  }
   294→
   295→  std::shared_ptr<ManagedContext> buildManagedContextUnderLock(
   296→      TransactionId tid, ManagedTrx& mtrx);
   297→
   298→  Result updateTransaction(
   299→      TransactionId tid, transaction::Status status, bool clearServers,
   300→      // TODO - use a better solution
   301→      std::string const& database =
   302→          "" /* leave empty to operate across all databases */);
   303→
   304→  /// @brief calls the callback function for each managed transaction
   305→  void iterateManagedTrx(
   306→      std::function<void(TransactionId, ManagedTrx const&)> const& callback,
   307→      bool details) const;
   308→
   309→  static double ttlForType(ManagerFeature const& feature,
   310→                           Manager::MetaType type);
   311→
   312→  bool transactionIdExists(TransactionId tid) const;
   313→
   314→  bool storeManagedState(TransactionId tid,
   315→                         std::shared_ptr<arangodb::TransactionState> state,
   316→                         double ttl);
   317→
   318→  bool isAuthorized(ManagedTrx const& trx) const;
   319→  bool isAuthorized(ManagedTrx const& trx, std::string_view database) const;
   320→
   321→  static std::string buildContextFromState(TransactionState& state,
   322→                                           MetaType type);
   323→
   324→ private:
   325→  ManagerFeature& _feature;
   326→
   327→  struct {
   328→    // a lock protecting _managed
   329→    mutable basics::ReadWriteLock _lock;
   330→
   331→    // managed transactions, seperate lifetime from above
   332→    std::unordered_map<TransactionId, ManagedTrx> _managed;
   333→  } _transactions[numBuckets];
   334→
   335→  /// Nr of running transactions
   336→  std::atomic<uint64_t> _nrRunning;
   337→
   338→  std::atomic<bool> _disallowInserts;
   339→
   340→  std::mutex _hotbackupMutex;  // Makes sure that we only ever get or release
   341→                               // the write lock and adjust _writeLockHeld at
   342→                               // the same time.
   343→  basics::ReadWriteLock _hotbackupCommitLock;
   344→  bool _hotbackupCommitLockHeld;
   345→
   346→  double _streamingLockTimeout;
   347→
   348→  std::atomic<bool> _softShutdownOngoing;
   349→
   350→#ifdef ARANGODB_ENABLE_MAINTAINER_MODE
   351→  /// @brief a history of currently ongoing and recently finished
   352→  /// transactions. currently only used for testing. NOT AVAILABLE
   353→  /// IN PRODUCTION!
   354→  std::unique_ptr<History> _history;
   355→#endif
   356→};
   357→
   358→// this RAII object is responsible for increasing and decreasing the
   359→// number of running transactions in the manager safely, so that it can't
   360→// be forgotten.
   361→class CounterGuard {
   362→  CounterGuard(CounterGuard const&) = delete;
   363→  CounterGuard& operator=(CounterGuard const&) = delete;
   364→
   365→ public:
   366→  explicit CounterGuard(Manager& manager);
   367→  ~CounterGuard();
   368→
   369→ private:
   370→  Manager& _manager;
   371→};
   372→
   373→}  // namespace transaction
   374→}  // namespace arangodb
